let start = flow.get("start");
let gain = flow.get("gain");

let t = (Date.now() - start) / 1000;

if (t < 10) {

    let f0 = 0.2;
    let f1 = 2.0;
    let k = (f1 - f0) / 10;

    msg.payload = Math.sin(
        2 * Math.PI * (f0 * t + 0.5 * k * t * t)
    ) * gain;
}
else {
    msg.payload = 0;
}

return msg;

