let start = flow.get("start");
let gain = flow.get("gain");

let t = (Date.now() - start) / 1000;

let step = Math.floor(t) + 1;
if (t < 10 && (step - 1) % 2) {
    msg.payload = (step / 10) * gain;
}
else {
    msg.payload = 0;
}

